import { cloneElement, isValidElement } from 'react';

import includes from '@andes/common/build/utils/includes';
import warning from '@andes/common/build/utils/warning';
import { WARNING_BUTTON_SWITCH_ITEM_SMALL, WARNING_BUTTON_SIZE, WARNING_BADGE_SIZE } from '../constants/warnings';

/**
 * @param {import('react').ReactElement} rightContent
 * @param {'large' | 'medium' | 'small'} [itemSize]
 */
const getVerifiedRightContent = (rightContent, itemSize) => {
  if (isValidElement(rightContent)) {
    // @ts-expect-error TS doesn't recognize that displayName is a prop of type
    if (rightContent.type?.displayName === 'Button') {
      if (itemSize === 'small') {
        warning(false, WARNING_BUTTON_SWITCH_ITEM_SMALL);
        return undefined;
      }

      if (rightContent.props?.size !== 'medium') {
        warning(false, WARNING_BUTTON_SIZE);
        return cloneElement(rightContent, { size: 'medium' });
      }
    }

    // @ts-expect-error TS doesn't recognize that displayName is a prop of type
    if (includes(['Pill', 'PillIcon'], rightContent.type?.displayName) && rightContent?.props?.size !== 'small') {
      warning(false, WARNING_BADGE_SIZE);
      return cloneElement(rightContent, { size: 'small' });
    }

    // @ts-expect-error TS doesn't recognize that displayName is a prop of type
    if (rightContent.type?.displayName === 'Switch' && itemSize === 'small') {
      warning(false, WARNING_BUTTON_SWITCH_ITEM_SMALL);
      return undefined;
    }
  }


  return rightContent;
};

export default getVerifiedRightContent;
